text:
Flavor Description

flavor_desc &lt;- ice_cream |&gt; 
  count(flavor_descr) |&gt; 
  arrange(-n)


icecream_sub &lt;- ice_cream |&gt; 
  filter(flavor_descr %in% flavor_desc$flavor_descr[1:5])

ggplot(icecream_sub,
       aes(x = priceper1,
           fill = flavor_descr)) +
  geom_density(alpha = .25)
